-- ----------------------------------------------------------------------------
-- vw_procedure_versions: Versioned procedure specifications. Maps to pko:Procedure plus DCAT version relations and PKO versionNumber/newVersionMotivation/changelogDescription.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_versions CASCADE;
CREATE VIEW vw_procedure_versions WITH (security_invoker = ON) AS
SELECT
  t.procedure_version_id,                                                       -- Stored logical identifier for one ProcedureVersions row.
  calc_procedure_versions_name(t.procedure_version_id) AS name,                 -- Human-readable calculated display alias for the ProcedureVersions row.
  t.procedure,                                                                  -- Abstract procedure of which this is a version.
  t.version_number,                                                             -- Version number; maps to pko:versionNumber.
  t.title,                                                                      -- Version-specific title.
  t.status,                                                                     -- PKO procedure status individual: Draft, Validation, Approval, Approved, Deprecated, or Archived.
  t.issued_at,                                                                  -- Issue timestamp; maps to dcterms:issued.
  t.modified_at,                                                                -- Last semantic modification; maps to dcterms:modified.
  t.created_by_agent,                                                           -- Agent that created the version; maps to dcterms:creator.
  t.modified_by_agent,                                                          -- Agent that last modified the version; maps to pko:wasModifiedBy.
  t.new_version_motivation,                                                     -- Reason for the new version; maps to pko:newVersionMotivation.
  t.changelog_description,                                                      -- Semantic change description; maps to pko:changelogDescription.
  t.is_current,                                                                 -- TRUE when this is the current version.
  calc_procedure_versions_count_of_steps(t.procedure_version_id) AS count_of_steps,-- Number of steps in this version.
  calc_procedure_versions_count_of_open_knowledge_gaps(t.procedure_version_id) AS count_of_open_knowledge_gaps,-- Open knowledge gaps for this version.
  calc_procedure_versions_is_ready_for_execution(t.procedure_version_id) AS is_ready_for_execution,-- TRUE when approved, populated, and free of blocking knowledge gaps.
  calc_procedure_versions_specified_step_count(t.procedure_version_id) AS specified_step_count,-- How many steps the specification defines for this version.
  calc_procedure_versions_overdue_review_count(t.procedure_version_id) AS overdue_review_count,-- How many reviews of this procedure version are past due.
  calc_procedure_versions_open_change_request_count(t.procedure_version_id) AS open_change_request_count,-- How many change requests are open against this version.
  calc_procedure_versions_open_high_severity_gap_count(t.procedure_version_id) AS open_high_severity_gap_count,-- How many high-severity knowledge gaps are open against this version.
  calc_procedure_versions_is_fit_to_execute(t.procedure_version_id) AS is_fit_to_execute,-- TRUE when this version is approved, current on review, and carries no open change request or high-severity gap.
  calc_procedure_versions_steward_review_cadence_days(t.procedure_version_id) AS steward_review_cadence_days,-- The review cadence promised by this version's stewardship assignment, in days. Summed because a version has at most one active steward; this is the hop that lets ReviewEvents resolve the promise via a primary-key match.
  calc_procedure_versions_count_of_stewardship_assignments(t.procedure_version_id) AS count_of_stewardship_assignments,-- How many stewardship assignments of any vintage point at this version.
  calc_procedure_versions_has_any_steward(t.procedure_version_id) AS has_any_steward,-- TRUE if any stewardship assignment has ever named this version.
  calc_procedure_versions_is_live(t.procedure_version_id) AS is_live,           -- TRUE when this version is in a state where somebody could execute it.
  calc_procedure_versions_is_unstewarded(t.procedure_version_id) AS is_unstewarded,-- TRUE when no stewardship assignment names this version.
  calc_procedure_versions_is_live_and_unstewarded(t.procedure_version_id) AS is_live_and_unstewarded,-- TRUE when an executable version has nobody accountable for keeping it healthy.
  calc_procedure_versions_count_of_open_blocking_gaps(t.procedure_version_id) AS count_of_open_blocking_gaps,-- How many open blocking gaps stand against this version.
  calc_procedure_versions_has_open_blocking_gap(t.procedure_version_id) AS has_open_blocking_gap,-- TRUE when at least one open blocking gap stands against this version.
  calc_procedure_versions_is_live_with_blocking_gap(t.procedure_version_id) AS is_live_with_blocking_gap,-- TRUE when an executable version carries an unresolved blocking knowledge gap.
  calc_procedure_versions_should_not_be_executable(t.procedure_version_id) AS should_not_be_executable,-- TRUE when the model says this version is ready to execute while a blocking gap is open against it.
  calc_procedure_versions_count_of_unapproved_reliance_fragments(t.procedure_version_id) AS count_of_unapproved_reliance_fragments,-- How many unapproved claims this version is relying on.
  calc_procedure_versions_runs_on_unapproved_knowledge(t.procedure_version_id) AS runs_on_unapproved_knowledge,-- TRUE when this version depends on at least one claim the knowledge authority has not approved.
  calc_procedure_versions_count_of_overdue_gaps(t.procedure_version_id) AS count_of_overdue_gaps,-- How many acknowledged unknowns against this version have outlived their tolerance.
  calc_procedure_versions_count_of_change_requests(t.procedure_version_id) AS count_of_change_requests,-- How many change requests have ever been raised against this version.
  calc_procedure_versions_count_of_review_events(t.procedure_version_id) AS count_of_review_events,-- How many review events have ever been recorded against this version.
  calc_procedure_versions_has_governance_record(t.procedure_version_id) AS has_governance_record,-- TRUE when at least one change request or review event exists for this version.
  calc_procedure_versions_days_since_modified(t.procedure_version_id) AS days_since_modified,-- Days since this version's content was last changed.
  calc_procedure_versions_days_since_last_review(t.procedure_version_id) AS days_since_last_review,-- Days since the most recent review of this version.
  calc_procedure_versions_was_modified_since_last_review(t.procedure_version_id) AS was_modified_since_last_review,-- TRUE when the version was edited more recently than it was reviewed.
  calc_procedure_versions_modifier_is_authority(t.procedure_version_id) AS modifier_is_authority,-- The kind of agent that last modified this version.
  calc_procedure_versions_has_unwitnessed_change(t.procedure_version_id) AS has_unwitnessed_change,-- TRUE when a live version's current content postdates every review it has had.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM procedure_versions t;

